import express from 'express';
import cors from 'cors';
import helmet from 'helmet';
import { getDatabase, runMigrations, seedData } from './db/database.js';
import { createBookRoutes } from './routes/books.js';
import { createMemberRoutes } from './routes/members.js';
import { createLoanRoutes } from './routes/loans.js';
import { createReservationRoutes } from './routes/reservations.js';
import { createFineRoutes } from './routes/fines.js';
import { expireStaleReservations } from './services/reservationService.js';
import SwaggerParser from '@apidevtools/swagger-parser';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const app = express();
const PORT = process.env.PORT || 3001;

// Initialize database
const db = getDatabase();
runMigrations(db);
seedData(db);

// Validate OpenAPI spec on boot
const openApiPath = join(__dirname, '../openapi.yaml');
try {
  await SwaggerParser.validate(openApiPath);
  console.log('OpenAPI spec is valid');
} catch (error) {
  console.error('OpenAPI spec validation failed:', error);
  process.exit(1);
}

// Middleware
app.use(helmet());
app.use(cors({
  origin: 'http://localhost:5173'
}));
app.use(express.json());

// Expire stale reservations on every request (AC-5.5)
app.use((_req, _res, next) => {
  expireStaleReservations(db);
  next();
});

// Routes
app.use('/api/books', createBookRoutes(db));
app.use('/api/members', createMemberRoutes(db));
app.use('/api/loans', createLoanRoutes(db));
app.use('/api/reservations', createReservationRoutes(db));
app.use('/api/fines', createFineRoutes(db));

// Health check
app.get('/health', (_req, res) => {
  res.json({ status: 'ok' });
});

// Error handler
app.use((err: Error, _req: express.Request, res: express.Response, _next: express.NextFunction) => {
  console.error(err);
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;

import { Router } from 'express';
import { z } from 'zod';
import type { DatabaseInstance } from '../db/database.js';
import * as bookService from '../services/bookService.js';
import { NotFoundError, ConflictError } from '../errors.js';

const router = Router();

const createBookSchema = z.object({
  title: z.string().min(1),
  author: z.string().min(1),
  isbn: z.string().min(1),
  total_copies: z.number().int().min(1)
});

export function createBookRoutes(db: DatabaseInstance) {
  // GET /api/books - List all books
  router.get('/', (_req, res) => {
    try {
      const books = bookService.listBooks(db);
      res.json(books);
    } catch (error) {
      res.status(500).json({ error: 'Internal server error' });
    }
  });

  // GET /api/books/:id - Get single book
  router.get('/:id', (req, res) => {
    try {
      const book = bookService.getBook(db, req.params.id);
      res.json(book);
    } catch (error) {
      if (error instanceof NotFoundError) {
        res.status(404).json({ error: 'Book not found' });
      } else {
        res.status(500).json({ error: 'Internal server error' });
      }
    }
  });

  // POST /api/books - Create a book
  router.post('/', (req, res) => {
    try {
      const input = createBookSchema.parse(req.body);
      const book = bookService.createBook(db, input);
      res.status(201).json(book);
    } catch (error) {
      if (error instanceof z.ZodError) {
        res.status(400).json({ error: 'Invalid input', details: error.errors });
      } else if (error instanceof ConflictError) {
        res.status(409).json({ error: error.message });
      } else {
        res.status(500).json({ error: 'Internal server error' });
      }
    }
  });

  return router;
}

import { Router } from 'express';
import { z } from 'zod';
import type { DatabaseInstance } from '../db/database.js';
import * as memberService from '../services/memberService.js';
import * as loanService from '../services/loanService.js';
import * as reservationService from '../services/reservationService.js';
import * as fineService from '../services/fineService.js';
import { NotFoundError, ConflictError } from '../errors.js';

const router = Router();

const createMemberSchema = z.object({
  name: z.string().min(1),
  email: z.string().email()
});

export function createMemberRoutes(db: DatabaseInstance) {
  // GET /api/members - List all members
  router.get('/', (_req, res) => {
    try {
      const members = memberService.listMembers(db);
      res.json(members);
    } catch (error) {
      res.status(500).json({ error: 'Internal server error' });
    }
  });

  // GET /api/members/:id - Get single member with stats
  router.get('/:id', (req, res) => {
    try {
      const member = memberService.getMember(db, req.params.id);
      res.json(member);
    } catch (error) {
      if (error instanceof NotFoundError) {
        res.status(404).json({ error: 'Member not found' });
      } else {
        res.status(500).json({ error: 'Internal server error' });
      }
    }
  });

  // POST /api/members - Create a member
  router.post('/', (req, res) => {
    try {
      const input = createMemberSchema.parse(req.body);
      const member = memberService.createMember(db, input);
      res.status(201).json(member);
    } catch (error) {
      if (error instanceof z.ZodError) {
        res.status(400).json({ error: 'Invalid input', details: error.errors });
      } else if (error instanceof ConflictError) {
        res.status(409).json({ error: error.message });
      } else {
        res.status(500).json({ error: 'Internal server error' });
      }
    }
  });

  // GET /api/members/:id/loans - Get member's active loans
  router.get('/:id/loans', (req, res) => {
    try {
      const loans = loanService.getActiveLoansForMember(db, req.params.id);
      res.json(loans);
    } catch (error) {
      res.status(500).json({ error: 'Internal server error' });
    }
  });

  // GET /api/members/:id/loans/history - Get member's loan history
  router.get('/:id/loans/history', (req, res) => {
    try {
      const loans = loanService.getLoanHistoryForMember(db, req.params.id);
      res.json(loans);
    } catch (error) {
      res.status(500).json({ error: 'Internal server error' });
    }
  });

  // GET /api/members/:id/reservations - Get member's reservations
  router.get('/:id/reservations', (req, res) => {
    try {
      const reservations = reservationService.getReservationsForMember(db, req.params.id);
      res.json(reservations);
    } catch (error) {
      res.status(500).json({ error: 'Internal server error' });
    }
  });

  // GET /api/members/:id/fines - Get member's unpaid fines
  router.get('/:id/fines', (req, res) => {
    try {
      const fines = fineService.getUnpaidFinesForMember(db, req.params.id);
      res.json(fines);
    } catch (error) {
      res.status(500).json({ error: 'Internal server error' });
    }
  });

  return router;
}

import { Router } from 'express';
import { z } from 'zod';
import type { DatabaseInstance } from '../db/database.js';
import * as reservationService from '../services/reservationService.js';
import { NotFoundError, ConflictError } from '../errors.js';

const router = Router();

const createReservationSchema = z.object({
  member_id: z.string().uuid(),
  book_id: z.string().uuid()
});

export function createReservationRoutes(db: DatabaseInstance) {
  // POST /api/reservations - Create a reservation
  router.post('/', (req, res) => {
    try {
      const input = createReservationSchema.parse(req.body);
      const reservation = reservationService.createReservation(db, input);
      res.status(201).json(reservation);
    } catch (error) {
      if (error instanceof z.ZodError) {
        res.status(400).json({ error: 'Invalid input', details: error.errors });
      } else if (error instanceof NotFoundError) {
        res.status(404).json({ error: error.message });
      } else if (error instanceof ConflictError) {
        res.status(409).json({ error: error.message });
      } else {
        res.status(500).json({ error: 'Internal server error' });
      }
    }
  });

  // POST /api/reservations/:id/cancel - Cancel a reservation
  router.post('/:id/cancel', (req, res) => {
    try {
      reservationService.cancelReservation(db, req.params.id);
      res.json({ success: true });
    } catch (error) {
      if (error instanceof NotFoundError) {
        res.status(404).json({ error: error.message });
      } else if (error instanceof ConflictError) {
        res.status(409).json({ error: error.message });
      } else {
        res.status(500).json({ error: 'Internal server error' });
      }
    }
  });

  // POST /api/reservations/expire - Trigger expiration of stale reservations
  router.post('/expire', (_req, res) => {
    try {
      reservationService.expireStaleReservations(db);
      res.json({ success: true });
    } catch (error) {
      res.status(500).json({ error: 'Internal server error' });
    }
  });

  return router;
}

import { test, expect } from '@playwright/test';

test.describe('Lending', () => {
  test('AC-3.1: POST /api/loans creates a loan', async ({ request }) => {
    // Create a book
    const bookRes = await request.post('/api/books', {
      data: {
        title: 'Loan Test Book',
        author: 'Author',
        isbn: `loan-book-${Date.now()}`,
        total_copies: 3
      }
    });
    const book = await bookRes.json();

    // Create a member
    const memberRes = await request.post('/api/members', {
      data: {
        name: 'Loan Test Member',
        email: `loan-member-${Date.now()}@example.com`
      }
    });
    const member = await memberRes.json();

    // Create loan
    const loanRes = await request.post('/api/loans', {
      data: {
        member_id: member.id,
        book_id: book.id
      }
    });

    expect(loanRes.status()).toBe(201);

    const loan = await loanRes.json();
    expect(loan).toHaveProperty('due_at');
    expect(loan.returned_at).toBeNull();
  });

  test('AC-3.3: Loan rejected for suspended member', async ({ request }) => {
    // This test requires seed data with a suspended member
    const membersRes = await request.get('/api/members');
    const members = await membersRes.json();
    const suspendedMember = members.find((m: { status: string }) => m.status === 'suspended');

    if (!suspendedMember) {
      test.skip();
      return;
    }

    // Get an available book
    const booksRes = await request.get('/api/books');
    const books = await booksRes.json();
    const availableBook = books.find((b: { available_copies: number }) => b.available_copies > 0);

    if (!availableBook) {
      test.skip();
      return;
    }

    const loanRes = await request.post('/api/loans', {
      data: {
        member_id: suspendedMember.id,
        book_id: availableBook.id
      }
    });

    expect(loanRes.status()).toBe(403);
    const body = await loanRes.json();
    expect(body.error).toBe('Member is suspended');
  });
});

test.describe('Returns', () => {
  test('AC-4.1: POST /api/loans/:id/return marks loan returned', async ({ request }) => {
    // Create test data
    const bookRes = await request.post('/api/books', {
      data: {
        title: 'Return Test Book',
        author: 'Author',
        isbn: `return-book-${Date.now()}`,
        total_copies: 2
      }
    });
    const book = await bookRes.json();

    const memberRes = await request.post('/api/members', {
      data: {
        name: 'Return Test Member',
        email: `return-member-${Date.now()}@example.com`
      }
    });
    const member = await memberRes.json();

    // Create loan
    const loanRes = await request.post('/api/loans', {
      data: {
        member_id: member.id,
        book_id: book.id
      }
    });
    const loan = await loanRes.json();

    // Return book
    const returnRes = await request.post(`/api/loans/${loan.id}/return`);
    expect(returnRes.ok()).toBeTruthy();

    const returnedLoan = await returnRes.json();
    expect(returnedLoan.returned_at).not.toBeNull();
  });

  test('AC-4.3: Return already returned loan returns 409', async ({ request }) => {
    // Create test data
    const bookRes = await request.post('/api/books', {
      data: {
        title: 'Return Test Book 2',
        author: 'Author',
        isbn: `return-book2-${Date.now()}`,
        total_copies: 2
      }
    });
    const book = await bookRes.json();

    const memberRes = await request.post('/api/members', {
      data: {
        name: 'Return Test Member 2',
        email: `return-member2-${Date.now()}@example.com`
      }
    });
    const member = await memberRes.json();

    const loanRes = await request.post('/api/loans', {
      data: { member_id: member.id, book_id: book.id }
    });
    const loan = await loanRes.json();

    // First return
    await request.post(`/api/loans/${loan.id}/return`);

    // Second return should fail
    const secondReturn = await request.post(`/api/loans/${loan.id}/return`);
    expect(secondReturn.status()).toBe(409);
    const body = await secondReturn.json();
    expect(body.error).toBe('Loan already returned');
  });
});

test.describe('Reservations', () => {
  test('AC-5.1: POST /api/reservations creates a reservation', async ({ request }) => {
    // Create a book with no available copies (by creating a loan)
    const bookRes = await request.post('/api/books', {
      data: {
        title: 'Reservation Test Book',
        author: 'Author',
        isbn: `res-book-${Date.now()}`,
        total_copies: 1
      }
    });
    const book = await bookRes.json();

    const memberRes = await request.post('/api/members', {
      data: {
        name: 'Reservation Test Member',
        email: `res-member-${Date.now()}@example.com`
      }
    });
    const member = await memberRes.json();

    // Create a loan to make book unavailable
    await request.post('/api/loans', {
      data: { member_id: member.id, book_id: book.id }
    });

    // Create another member to make reservation
    const memberRes2 = await request.post('/api/members', {
      data: {
        name: 'Reservation Test Member 2',
        email: `res-member2-${Date.now()}@example.com`
      }
    });
    const member2 = await memberRes2.json();

    // Create reservation
    const resRes = await request.post('/api/reservations', {
      data: { member_id: member2.id, book_id: book.id }
    });

    expect(resRes.status()).toBe(201);
    const reservation = await resRes.json();
    expect(reservation.status).toBe('waiting');
  });

  test('AC-5.5: POST /api/reservations/expire expires stale reservations', async ({ request }) => {
    const res = await request.post('/api/reservations/expire');
    expect(res.ok()).toBeTruthy();
  });
});

test.describe('Fines', () => {
  test('AC-6.2: POST /api/fines/:id/pay marks fine as paid', async ({ request }) => {
    // This test requires a fine to exist
    // Skip if no fines available
    test.skip();
  });

  test('AC-6.3: Paying already paid fine returns 409', async ({ request }) => {
    test.skip();
  });
});
